mapper.select:
SELECT s.id, s.course_id, c.course_name, c.description, c.category, c.image_url, c.difficulty_level, c.duration_minutes, c.calories_min, c.calories_max, c.coach_id, u.username AS coach_name, u.avatar AS coach_avatar, s.day_of_week, s.session_date, s.start_time, s.end_time, s.status, s.capacity, s.booked_count, (s.capacity - s.booked_count) AS remaining_count, s.create_time FROM fitness_course_session s INNER JOIN fitness_course c ON s.course_id = c.id AND c.deleted = false LEFT JOIN sys_user u ON c.coach_id = u.id WHERE s.deleted = false AND s.session_date >= CURRENT_DATE
AND c.id = #{query.courseId}
AND c.category = #{query.category}
AND s.day_of_week = #{query.dayOfWeek}
AND s.session_date >= #{query.startDate}
AND s.session_date <= #{query.endDate}
AND (c.course_name LIKE '%' || #{query.keyword} || '%' OR u.username LIKE '%' || #{query.keyword} || '%')
AND c.coach_id = #{query.coachId}
ORDER BY s.session_date ASC, s.start_time ASC

SELECT s.id, s.session_date
FROM fitness_course_session s
WHERE s.course_id = #{courseId}
  AND s.deleted = false
  AND s.session_date <= #{maxDate}
ORDER BY s.session_date ASC
